```js
const express = require('express');
const app = express();

// --- Security headers (use helmet in production) ---
// npm install helmet
const helmet = require('helmet');
app.use(helmet());

// --- Body parsing with size limits (prevent payload flooding) ---
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// --- Rate limiting (prevent brute-force / DoS) ---
// npm install express-rate-limit
const rateLimit = require('express-rate-limit');
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate & sanitize any query params before use
  const { page = 1, limit = 20 } = req.query;
  const parsedPage  = parseInt(page,  10);
  const parsedLimit = parseInt(limit, 10);

  if (isNaN(parsedPage) || parsedPage < 1 ||
      isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 100) {
    return res.status(400).json({ error: 'Invalid pagination parameters.' });
  }

  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob',   email: 'bob@example.com'  },
  ]);
});

// --- 404 handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found.' });
});

// --- Centralized error handler (must have 4 params) ---
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  console.error(err); // log internally; never expose to client
  const status = err.status || err.statusCode || 500;
  res.status(status).json({
    error: process.env.NODE_ENV === 'production'
      ? 'An unexpected error occurred.'
      : err.message,
  });
});

// --- Use environment variable for port ---
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

